<template><div class="pagination"><span>共 {{ total }} 条</span><div class="pagination-pages"><button class="page-btn" type="button" aria-label="上一页" :disabled="page<=1" @click="go(page-1)"><ChevronLeft :size="14"/></button><button v-for="p in pages" :key="p" class="page-btn" :class="{active:p===page}" type="button" @click="go(p)">{{ p }}</button><button class="page-btn" type="button" aria-label="下一页" :disabled="page>=totalPages" @click="go(page+1)"><ChevronRight :size="14"/></button></div></div></template>
<script setup lang="ts">
import { computed } from 'vue';import { ChevronLeft,ChevronRight } from 'lucide-vue-next';const props=defineProps<{total:number;page:number;size:number}>();const emit=defineEmits<{(e:'update:page',v:number):void}>();const totalPages=computed(()=>Math.max(1,Math.ceil(props.total/props.size)));const pages=computed(()=>{const a:number[]=[];let s=Math.max(1,props.page-2),e=Math.min(totalPages.value,s+4);s=Math.max(1,e-4);for(let i=s;i<=e;i++)a.push(i);return a});function go(p:number){if(p>=1&&p<=totalPages.value&&p!==props.page)emit('update:page',p)}
</script>
<style scoped>.pagination{display:flex;align-items:center;justify-content:space-between;padding:14px 20px;font-size:12px;color:var(--muted-foreground)}.pagination-pages{display:flex;gap:7px;align-items:center}.page-btn{min-width:32px;height:32px;display:grid;place-items:center;border:1px solid var(--border);border-radius:11px;background:white;color:var(--foreground);cursor:pointer;font:inherit;transition:all .2s}.page-btn:hover:not(:disabled){background:var(--accent);color:var(--primary);transform:translateY(-1px)}.page-btn.active{background:#e8f1ff;color:#155fc9;border-color:#c9ddfb;box-shadow:0 5px 12px rgba(23,105,224,.1);font-weight:700}.page-btn:disabled{opacity:.4;cursor:not-allowed}</style>
